INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Auto-scheduling$q$, $q$Generates shift schedules automatically based on demand forecasts, labor budgets, and employee availability.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Mobile time clock$q$, $q$Employees clock in and out via mobile app or tablet kiosk with GPS and photo verification.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Payroll integrations$q$, $q$Native integrations with Gusto, QuickBooks, ADP, Xero, and Square Payroll sync timesheets directly to payroll runs.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Shift swapping and open shifts$q$, $q$Employees can request swaps or claim open shifts through the mobile app, subject to manager approval rules.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Tasking and checklists$q$, $q$Managers assign shift-specific tasks and checklists that employees complete and confirm from the mobile app.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Labor cost forecasting$q$, $q$Wage budgeting and demand forecasting tools help managers avoid overstaffing and control labor spend in real time.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Team messaging$q$, $q$A built-in news feed and messaging layer keeps shift teams informed without relying on outside chat apps.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Compliance alerts$q$, $q$Break-rule reminders, overtime alerts, and fair workweek notifications help reduce labor law compliance risk.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Strong mobile apps make scheduling and time clocking easy for frontline, non-desk employees.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Payroll-agnostic integrations let businesses keep their existing payroll provider instead of switching systems.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Auto-scheduling based on demand forecasting can meaningfully reduce overstaffing costs.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Transparent per-user pricing with a free trial makes it easy for small operators to get started.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$A minimum monthly spend applies even to very small teams, raising the effective per-user cost for tiny businesses.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Advanced features like SSO and sandbox environments require the top Pro tier.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Some integrations and add-ons (Deputy HR, Analytics+) are priced separately from core plans.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Larger, more complex deployments often require custom enterprise pricing outside the published tiers.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$What does Deputy cost?$q$, $q$Deputy's self-serve plans start at $5 per user per month (Lite), with Core at $6.50 and Pro at $9 per user per month; a roughly 10% annual billing discount applies and a minimum monthly invoice spend of about $30 is charged across all plans.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Does Deputy integrate with payroll providers?$q$, $q$Yes, Deputy has native and partner integrations with payroll providers including Gusto, QuickBooks, ADP, Xero, and Square Payroll, allowing timesheet data to sync directly into payroll runs.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Is there a free trial of Deputy?$q$, $q$Yes, Deputy offers a free trial on all of its Lite, Core, and Pro plans.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Who founded Deputy and when?$q$, $q$Deputy was founded in 2008 in Sydney, Australia, by Ashik Ahmed and Steve Shelley.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$What industries use Deputy?$q$, $q$Deputy is most commonly used in retail, hospitality, healthcare, and other shift-based, multi-location industries that need to schedule hourly employees.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Does Deputy have mobile apps?$q$, $q$Yes, Deputy has native iOS and Android apps for both employees and managers, covering scheduling, time clocking, shift swaps, and messaging.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Multi-location retail scheduling$q$, $q$Retail chains use Deputy's demand-based auto-scheduling to staff stores according to forecasted foot traffic and sales, reducing both overstaffing and understaffing.$q$, $q$Retail operations managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Restaurant shift and payroll management$q$, $q$Restaurants use Deputy to build rosters, track hourly time and attendance, and sync timesheets directly into payroll to speed up pay runs.$q$, $q$Restaurant and hospitality owners$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Healthcare shift coverage$q$, $q$Healthcare facilities use Deputy to manage complex shift patterns, overtime compliance, and last-minute shift coverage for hourly clinical and support staff.$q$, $q$Healthcare facility managers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Lite$q$, $q$$5/user/month$q$, $q$Monthly or annual (annual discount available)$q$, NULL, $q$["Scheduling","Timesheets","Time clocking","Payroll integrations"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Core$q$, $q$$6.50/user/month$q$, $q$Monthly or annual (annual discount available)$q$, NULL, $q$["Everything in Lite","Auto-scheduling","Demand forecasting","Labor cost optimization","Wage budgeting"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$Pro$q$, $q$$9/user/month$q$, $q$Monthly or annual (annual discount available)$q$, NULL, $q$["Everything in Core","Single sign-on","Custom access levels","Sandbox environment","24/7 live chat support","Analytics+ and Messaging+ bundled"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Deputy is a workforce management platform purpose-built for businesses that schedule shift-based or hourly employees, such as retailers, restaurants, healthcare providers, and hospitality operators. It combines employee scheduling, time and attendance tracking, task management, and payroll integration into a single cloud-based system accessible from web and mobile apps.$q$, $q$Founded in Sydney in 2008 by Ashik Ahmed and Steve Shelley, Deputy has grown into a globally used platform serving tens of thousands of businesses, with dual headquarters in Sydney and Atlanta and total venture funding of roughly $143 million.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Deputy's scheduling engine supports drag-and-drop rostering, auto-scheduling driven by demand forecasts, and self-service shift swaps for employees, all synced in real time across the web app and native iOS/Android apps.$q$, $q$Time and attendance is handled through mobile clock-in, kiosk mode on tablets, and GPS/photo verification, with timesheet data flowing directly into payroll providers like Gusto, QuickBooks, ADP, and Xero to eliminate manual re-entry.$q$, $q$Additional modules cover shift tasking and checklists, in-app team messaging, labor cost and wage budgeting analytics, and an HR add-on for onboarding and document management.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Deputy offers three self-serve plans priced per user per month: Lite ($5) for core scheduling and time clocking, Core ($6.50) which adds auto-scheduling and labor forecasting, and Pro ($9) which adds SSO, custom access levels, and 24/7 support plus bundled analytics and messaging add-ons.$q$, $q$All plans include a free trial and roughly a 10% discount for annual billing, with a minimum monthly spend of around $30 per invoice applied across every tier.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ebc6d4d6-9473-4cc7-b9e8-18f595f9b246', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f510c6a5-cbc9-401c-86fa-13a9b3bcc298', $q$No-code Flows builder$q$, $q$Visually design authentication and user-journey flows as a flowchart, then deploy via SDK without custom auth code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f510c6a5-cbc9-401c-86fa-13a9b3bcc298', $q$Passwordless authentication$q$, $q$Supports magic links, one-time codes, and passkey/WebAuthn login in addition to traditional credentials.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f510c6a5-cbc9-401c-86fa-13a9b3bcc298', $q$Single sign-on$q$, $q$SAML and OIDC SSO support for both consumer and multi-tenant B2B applications, including zero-downtime SSO migration.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f510c6a5-cbc9-401c-86fa-13a9b3bcc298', $q$Multi-factor authentication$q$, $q$Configurable MFA and step-up authentication policies applied directly within visual flows.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f510c6a5-cbc9-401c-86fa-13a9b3bcc298', $q$Native multi-tenancy$q$, $q$Built-in tenant management lets B2B SaaS companies manage per-customer authentication and access policies.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f510c6a5-cbc9-401c-86fa-13a9b3bcc298', $q$Fine-grained access control$q$, $q$Role-based and attribute-based access control for managing permissions across applications and tenants.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f510c6a5-cbc9-401c-86fa-13a9b3bcc298', $q$Bot and fraud protection$q$, $q$Built-in bot detection and account-takeover prevention to protect sign-up and login flows.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f510c6a5-cbc9-401c-86fa-13a9b3bcc298', $q$Agentic identity support$q$, $q$Extends identity and access management to cover AI agents acting on behalf of users within applications.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f510c6a5-cbc9-401c-86fa-13a9b3bcc298', $q$Generous free tier (7,500 MAUs) compared to many CIAM competitors, making it accessible for early-stage products.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f510c6a5-cbc9-401c-86fa-13a9b3bcc298', $q$No-code Flows builder reduces engineering time spent building and maintaining custom authentication logic.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f510c6a5-cbc9-401c-86fa-13a9b3bcc298', $q$Strong multi-tenancy and SSO-migration tooling aimed specifically at B2B SaaS sales cycles.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f510c6a5-cbc9-401c-86fa-13a9b3bcc298', $q$Founding team's security pedigree (Demisto/Palo Alto Networks) lends credibility for security-conscious buyers.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f510c6a5-cbc9-401c-86fa-13a9b3bcc298', $q$Higher tiers (Pro, Growth) require annual commitments with usage-based overage billing, which can complicate budgeting.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f510c6a5-cbc9-401c-86fa-13a9b3bcc298', $q$As a newer entrant (founded 2022), it has a smaller market track record than incumbents like Auth0 or Okta.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f510c6a5-cbc9-401c-86fa-13a9b3bcc298', $q$Advanced compliance features (HIPAA BAA, FedRAMP High) are gated behind the Growth tier or above.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f510c6a5-cbc9-401c-86fa-13a9b3bcc298', $q$Enterprise pricing is custom and not published, requiring a sales conversation for large-scale deployments.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f510c6a5-cbc9-401c-86fa-13a9b3bcc298', $q$Is Descope free to use?$q$, $q$Yes, Descope offers a Free Forever tier that includes 7,500 monthly active users, 10 tenants, and 3 SSO connections at no cost.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f510c6a5-cbc9-401c-86fa-13a9b3bcc298', $q$Who founded Descope and when?$q$, $q$Descope was founded in April 2022 by an eight-person Israeli founder team led by CEO Slavik Markovich, several of whom previously built the SOAR company Demisto, which was acquired by Palo Alto Networks.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f510c6a5-cbc9-401c-86fa-13a9b3bcc298', $q$How much does Descope's Pro plan cost?$q$, $q$Descope's Pro tier starts at $249 per month, billed annually, and includes 10,000 monthly active users, 5 SSO connections, and web/email support.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f510c6a5-cbc9-401c-86fa-13a9b3bcc298', $q$Does Descope require code to set up authentication?$q$, $q$No, Descope offers a no-code drag-and-drop Flows builder for designing authentication journeys, while also providing SDKs and APIs for teams that want deeper programmatic control.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f510c6a5-cbc9-401c-86fa-13a9b3bcc298', $q$What is Descope's SSO migration feature?$q$, $q$Descope's Growth tier includes zero-downtime SSO migration, which lets a customer consume and migrate an existing customer's SSO configuration via DNS redirects without requiring the tenant admin to redo setup.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f510c6a5-cbc9-401c-86fa-13a9b3bcc298', $q$Who are Descope's main competitors?$q$, $q$Descope competes primarily with Auth0 (Okta), WorkOS, Frontegg, Clerk, FusionAuth, and Amazon Cognito in the customer identity and access management space.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f510c6a5-cbc9-401c-86fa-13a9b3bcc298', $q$B2B SaaS multi-tenant authentication$q$, $q$SaaS companies use Descope's native multi-tenancy to manage separate authentication and SSO configurations per enterprise customer without building custom tenant logic.$q$, $q$B2B SaaS engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f510c6a5-cbc9-401c-86fa-13a9b3bcc298', $q$Consumer app passwordless login$q$, $q$Consumer applications use Descope's Flows builder to roll out passwordless and passkey-based login to reduce sign-up friction and password-related support tickets.$q$, $q$Product and growth engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f510c6a5-cbc9-401c-86fa-13a9b3bcc298', $q$Enterprise SSO onboarding$q$, $q$Enterprises use Descope's SSO migration tooling to onboard large customers with existing SSO setups without lengthy IT coordination projects.$q$, $q$Enterprise sales engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f510c6a5-cbc9-401c-86fa-13a9b3bcc298', $q$Free Forever$q$, $q$$0$q$, $q$No commitment$q$, NULL, $q$["7,500 MAUs","10 tenants","3 SSO connections","1 federated app","All auth methods","RBAC and MFA","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f510c6a5-cbc9-401c-86fa-13a9b3bcc298', $q$Pro$q$, $q$$249/month$q$, $q$Annual commitment, usage-based overages$q$, NULL, $q$["10,000 MAUs","35 tenants","5 SSO connections","Custom domain","Google One Tap","Web/email support","SOC 2 reports"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f510c6a5-cbc9-401c-86fa-13a9b3bcc298', $q$Growth$q$, $q$$799/month$q$, $q$Annual commitment, usage-based overages$q$, NULL, $q$["25,000 MAUs","100 tenants","10 SSO connections","Bot protection","Zero-downtime SSO migration","SCIM provisioning","HIPAA BAA support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f510c6a5-cbc9-401c-86fa-13a9b3bcc298', $q$Enterprise$q$, $q$Custom$q$, $q$Annual contract$q$, NULL, $q$["Unlimited test/anonymous users","Tiered discounts","Dedicated CS engineer","Custom deployments"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f510c6a5-cbc9-401c-86fa-13a9b3bcc298', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Descope is a customer identity and access management (CIAM) platform that helps developers build authentication, authorization, and user-journey flows using a no-code/low-code drag-and-drop builder alongside SDKs and APIs for deeper customization.$q$, $q$Founded in 2022 by a team of Israeli entrepreneurs previously behind the SOAR company Demisto (acquired by Palo Alto Networks), Descope is headquartered in Los Altos, California, and has raised roughly $88 million in seed funding led by Lightspeed Venture Partners and GGV Capital.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f510c6a5-cbc9-401c-86fa-13a9b3bcc298', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform's Flows builder lets teams visually design sign-up, sign-in, MFA, and account-recovery journeys, then deploy them through SDKs without writing custom authentication logic from scratch.$q$, $q$Descope supports passwordless authentication, passkeys, social login, multi-factor authentication, SAML/OIDC single sign-on, native multi-tenancy for B2B applications, fine-grained role-based access control, and bot/account-takeover protection.$q$, $q$Enterprise-focused capabilities include zero-downtime SSO migration, SCIM provisioning, multi-region data residency, and compliance support for SOC 2, HIPAA, and FedRAMP High.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f510c6a5-cbc9-401c-86fa-13a9b3bcc298', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Descope's Free Forever tier includes 7,500 monthly active users, 10 tenants, and 3 SSO connections at no cost, making it one of the more generous free tiers among CIAM providers.$q$, $q$Paid tiers start with Pro at $249/month (10,000 MAUs) and Growth at $799/month (25,000 MAUs, bot protection, SSO migration tooling), both billed annually with usage-based overages, while Enterprise moves to custom contract pricing.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f510c6a5-cbc9-401c-86fa-13a9b3bcc298', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f510c6a5-cbc9-401c-86fa-13a9b3bcc298', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
