INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f510c6a5-cbc9-401c-86fa-13a9b3bcc298', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f510c6a5-cbc9-401c-86fa-13a9b3bcc298', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Transcript-based editing$q$, $q$Edit audio and video by editing a synchronized text transcript instead of a traditional timeline.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Overdub voice cloning$q$, $q$Generate new spoken audio in a trained voice model by typing text, useful for fixing mistakes without re-recording.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Studio Sound$q$, $q$AI audio cleanup that removes background noise and enhances voice quality to approximate studio recording.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Filler word and silence removal$q$, $q$Automatically detects and removes ums, pauses, and dead air from recordings.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Underlord AI assistant$q$, $q$Executes editing commands and suggestions from natural-language prompts within the editor.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Screen recording$q$, $q$Built-in screen capture for tutorials, demos, and webinar-style content.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Green screen and eye contact correction$q$, $q$AI video tools that remove backgrounds and correct on-camera eye contact automatically.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Real-time collaboration$q$, $q$Multiple editors can work on the same project simultaneously, similar to a shared document.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Transcript-based editing dramatically lowers the skill barrier for cutting and rearranging recordings.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Overdub and Studio Sound provide AI capabilities not commonly bundled together in competing editors.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Flexible plan structure serves solo podcasters up through small video production teams.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Backed by significant funding, including from the OpenAI Startup Fund, supporting continued AI feature development.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Free and lower tiers cap monthly transcription hours, which can be limiting for high-volume creators.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Advanced AI features like Overdub require paid tiers and additional voice-model training time.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Less granular manual timeline control than dedicated professional editors like Premiere Pro.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Enterprise features such as SSO and security review require custom-priced plans.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$What makes Descript different from traditional video editors?$q$, $q$Descript lets users edit audio and video by editing a text transcript of the recording, rather than manipulating clips on a timeline, with AI keeping the transcript and media synchronized.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$How much does Descript cost?$q$, $q$Descript has a free plan with about 60 minutes of monthly transcription, then paid plans starting at $16/user/month (Hobbyist, billed annually) up to $50/user/month (Business, billed annually), plus a custom-priced Enterprise plan.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$What is Overdub in Descript?$q$, $q$Overdub is Descript's AI voice-cloning feature that lets users generate new spoken audio in their own trained voice by typing text, useful for correcting mistakes without re-recording.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Who founded Descript?$q$, $q$Descript was founded in 2017 by Andrew Mason, the former co-founder and CEO of Groupon.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Is Descript good for podcasters?$q$, $q$Yes, Descript's Creator plan is specifically positioned for podcasters and YouTubers, offering full AI editing tools including Overdub and Studio Sound.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Does Descript offer a free trial or free plan?$q$, $q$Descript offers a free plan (not just a trial) that includes about 60 minutes of transcription per month with watermarked exports.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Podcast production$q$, $q$Podcasters use Descript's transcript editor and Studio Sound to record, clean up audio, and publish episodes without traditional audio engineering skills.$q$, $q$Podcasters and audio creators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$YouTube and social video editing$q$, $q$Content creators use Descript to quickly cut long-form recordings into polished videos and short clips using text-based editing and filler-word removal.$q$, $q$YouTubers and social media creators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Marketing and internal video content$q$, $q$Marketing and L&D teams use Descript's screen recording and collaboration tools to produce product demos and training videos at scale.$q$, $q$Marketing and enablement teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["~60 minutes transcription/month","Watermarked exports","Core transcript editing"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Hobbyist$q$, $q$$16/user/month (annual) or $24/month$q$, $q$Monthly or annual$q$, NULL, $q$["~10 hours transcription/month","Basic AI tools","Watermark-free exports"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Creator$q$, $q$$24/user/month (annual) or $35/month$q$, $q$Monthly or annual$q$, NULL, $q$["~10 hours transcription/month","Full AI toolset","Overdub and Studio Sound"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Business$q$, $q$$50/user/month (annual) or $65/month$q$, $q$Monthly or annual$q$, NULL, $q$["~30 hours transcription/month","Team collaboration","Expanded export capacity"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$Enterprise$q$, $q$Custom$q$, $q$Annual contract$q$, NULL, $q$["Single sign-on","Dedicated support","Security review"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Descript is an AI-powered audio and video editing platform where users edit recordings by editing a text transcript rather than manipulating a traditional timeline, with AI keeping the transcript, audio, and video synchronized automatically.$q$, $q$Founded in 2017 by former Groupon CEO Andrew Mason, Descript is headquartered in San Francisco and has raised roughly $100 million in funding, including a Series C round led by the OpenAI Startup Fund.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Descript's transcript-based editor lets users cut, reorder, and edit recordings by editing text, while Overdub uses AI voice cloning to generate new spoken audio from typed text for fixing errors without re-recording.$q$, $q$Studio Sound automatically cleans up background noise and improves voice audio quality, while filler-word removal, green-screen effects, and eye-contact correction round out the AI production toolkit.$q$, $q$The platform also includes built-in screen recording, multitrack manual editing for finer control, and real-time collaboration for teams working on the same project.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Descript offers a Free plan with about 60 minutes of monthly transcription, followed by Hobbyist ($16/mo annual), Creator ($24/mo annual), and Business ($50/mo annual) tiers that expand transcription hours, AI features, and collaboration limits.$q$, $q$An Enterprise tier offers custom pricing with SSO, dedicated support, and security review, and annual billing saves up to 35% compared to month-to-month pricing across all paid plans.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', 'f24fb236-dfcf-452c-9b9e-02926f4383d9') ON CONFLICT DO NOTHING;
