INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('38565ec2-30ed-445f-b1d3-7ebd8fe67504', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bd90bf6d-4e0a-4e7e-ad8e-9a160bda7dbc', $q$Unified ticketing$q$, $q$Consolidates email, chat, phone, web form, and social inquiries into a single agent ticket queue.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bd90bf6d-4e0a-4e7e-ad8e-9a160bda7dbc', $q$Live chat$q$, $q$A customizable live chat widget for real-time customer conversations on the customer's website.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bd90bf6d-4e0a-4e7e-ad8e-9a160bda7dbc', $q$Self-service knowledge base$q$, $q$Customizable help center and community forum for customer self-service and deflecting tickets.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bd90bf6d-4e0a-4e7e-ad8e-9a160bda7dbc', $q$Cloud or self-hosted deployment$q$, $q$Deploy Deskpro as multi-tenant cloud SaaS or as self-hosted software on the customer's own infrastructure.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bd90bf6d-4e0a-4e7e-ad8e-9a160bda7dbc', $q$Automation and SLAs$q$, $q$Rule-based automation, escalation, and SLA tracking to manage response and resolution times.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bd90bf6d-4e0a-4e7e-ad8e-9a160bda7dbc', $q$AI-assisted ticket triage$q$, $q$AI tools suggest ticket categorization and reply drafts to speed up agent response times.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bd90bf6d-4e0a-4e7e-ad8e-9a160bda7dbc', $q$CRM-style contact management$q$, $q$Tracks organizations and contacts across support interactions for account-level context.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bd90bf6d-4e0a-4e7e-ad8e-9a160bda7dbc', $q$Custom branding and configurability$q$, $q$Deep customization of ticket forms, statuses, and workflows suited to enterprise and regulated environments.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bd90bf6d-4e0a-4e7e-ad8e-9a160bda7dbc', $q$Rare ability to run fully self-hosted/on-premise for organizations with strict data-residency or air-gap requirements.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bd90bf6d-4e0a-4e7e-ad8e-9a160bda7dbc', $q$Bootstrapped, profitable operating history for over two decades signals long-term stability.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bd90bf6d-4e0a-4e7e-ad8e-9a160bda7dbc', $q$Combines ticketing, live chat, and knowledge base in one product without needing separate add-on purchases.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bd90bf6d-4e0a-4e7e-ad8e-9a160bda7dbc', $q$Recent Series A funding is being used to accelerate AI features and enterprise capabilities.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bd90bf6d-4e0a-4e7e-ad8e-9a160bda7dbc', $q$Cloud pricing per agent is on the higher end compared to some competitors' entry-level plans.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bd90bf6d-4e0a-4e7e-ad8e-9a160bda7dbc', $q$Self-hosted deployment requires a 10-agent minimum, raising the cost floor for very small teams.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bd90bf6d-4e0a-4e7e-ad8e-9a160bda7dbc', $q$Newer to significant AI feature investment compared to some cloud-native competitors.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bd90bf6d-4e0a-4e7e-ad8e-9a160bda7dbc', $q$Publicly listed pricing may not reflect final enterprise contract terms, which require sales discussion.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bd90bf6d-4e0a-4e7e-ad8e-9a160bda7dbc', $q$Can Deskpro be self-hosted?$q$, $q$Yes, Deskpro offers a self-hosted, on-premise version of its software in addition to its cloud SaaS product, which is uncommon among modern helpdesk vendors.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bd90bf6d-4e0a-4e7e-ad8e-9a160bda7dbc', $q$How much does Deskpro cost?$q$, $q$Deskpro Cloud starts at $49 per agent per month for the Team plan, with Professional at $69 and Enterprise at $99 per agent per month; self-hosted On-Premise plans start at $59 per agent per month with a 10-agent minimum.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bd90bf6d-4e0a-4e7e-ad8e-9a160bda7dbc', $q$When was Deskpro founded?$q$, $q$Deskpro originated in 2001 as a project started at Oxford University by co-founders Christopher Padfield and Christopher Nadeau, with the company formally established shortly after.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bd90bf6d-4e0a-4e7e-ad8e-9a160bda7dbc', $q$Has Deskpro raised venture funding?$q$, $q$Deskpro operated profitably without outside investment for over 20 years before raising a $25 million Series A round led by Elsewhere Partners in 2024.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bd90bf6d-4e0a-4e7e-ad8e-9a160bda7dbc', $q$Where is Deskpro headquartered?$q$, $q$Deskpro's global headquarters is now in Austin, Texas; the company was originally headquartered in London, United Kingdom.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bd90bf6d-4e0a-4e7e-ad8e-9a160bda7dbc', $q$Does Deskpro offer a free trial?$q$, $q$Yes, Deskpro offers a free trial for prospective customers to evaluate its cloud helpdesk product.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bd90bf6d-4e0a-4e7e-ad8e-9a160bda7dbc', $q$Enterprise on-premise helpdesk$q$, $q$Enterprises and government agencies with strict data-residency requirements deploy Deskpro on their own infrastructure rather than a multi-tenant cloud service.$q$, $q$Enterprise IT and government support teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bd90bf6d-4e0a-4e7e-ad8e-9a160bda7dbc', $q$Multi-channel customer support$q$, $q$Support teams consolidate email, chat, phone, and social inquiries into a single Deskpro ticket queue to streamline agent workflows.$q$, $q$Customer support teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bd90bf6d-4e0a-4e7e-ad8e-9a160bda7dbc', $q$Self-service deflection$q$, $q$Companies use Deskpro's knowledge base and community forum to let customers resolve common issues without opening a ticket.$q$, $q$Customer support and success teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bd90bf6d-4e0a-4e7e-ad8e-9a160bda7dbc', $q$Cloud Team$q$, $q$$49/user/month$q$, $q$Monthly or annual$q$, NULL, $q$["Ticketing","Live chat","Knowledge base","Basic automation"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bd90bf6d-4e0a-4e7e-ad8e-9a160bda7dbc', $q$Cloud Professional$q$, $q$$69/user/month$q$, $q$Monthly or annual$q$, NULL, $q$["Everything in Team","Advanced automation","Reporting"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bd90bf6d-4e0a-4e7e-ad8e-9a160bda7dbc', $q$Cloud Enterprise$q$, $q$$99/user/month$q$, $q$Monthly or annual$q$, NULL, $q$["Everything in Professional","Advanced security","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bd90bf6d-4e0a-4e7e-ad8e-9a160bda7dbc', $q$On-Premise Professional$q$, $q$$59/user/month$q$, $q$Annual, 10-agent minimum$q$, NULL, $q$["Self-hosted deployment","Core ticketing and chat"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bd90bf6d-4e0a-4e7e-ad8e-9a160bda7dbc', $q$On-Premise Enterprise$q$, $q$$99/user/month$q$, $q$Annual, 10-agent minimum$q$, NULL, $q$["Self-hosted deployment","Advanced security and configurability"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bd90bf6d-4e0a-4e7e-ad8e-9a160bda7dbc', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Deskpro is a customer support and helpdesk platform offering ticketing, live chat, and a self-service knowledge base, distinguished by its option to deploy as either cloud SaaS or self-hosted, on-premise software.$q$, $q$Originating from a project started at Oxford University in 2001 by co-founders Christopher Padfield and Christopher Nadeau, Deskpro operated profitably and independently for over two decades before taking its first outside funding, a $25 million Series A led by Elsewhere Partners in 2024. The company is now headquartered in Austin, Texas, having originally been based in London.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bd90bf6d-4e0a-4e7e-ad8e-9a160bda7dbc', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Deskpro's ticketing system consolidates email, live chat, web forms, phone, and social channels into a single agent workspace, with automation rules, SLA tracking, and custom ticket statuses.$q$, $q$The platform includes a customizable self-service knowledge base, community forum, live chat widget, and a CRM-style contact/organization layer for tracking customer relationships across tickets.$q$, $q$Deskpro has added AI-assisted ticket triage and suggested replies to help agents reduce first-response times.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bd90bf6d-4e0a-4e7e-ad8e-9a160bda7dbc', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Deskpro Cloud is priced per agent per month across three tiers: Team ($49), Professional ($69), and Enterprise ($99), with annual billing offering roughly a 10% discount.$q$, $q$The self-hosted On-Premise product is licensed as an annual subscription with Professional at $59/user/month and Enterprise at $99/user/month, subject to a 10-agent minimum deployment.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('bd90bf6d-4e0a-4e7e-ad8e-9a160bda7dbc', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('bd90bf6d-4e0a-4e7e-ad8e-9a160bda7dbc', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('bd90bf6d-4e0a-4e7e-ad8e-9a160bda7dbc', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('bd90bf6d-4e0a-4e7e-ad8e-9a160bda7dbc', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b6b57d57-40f4-4d52-966d-761a1cafadb8', $q$Automatic time tracking$q$, $q$Starts and stops tracking automatically based on computer activity without requiring manual timers.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b6b57d57-40f4-4d52-966d-761a1cafadb8', $q$Productivity scoring$q$, $q$Classifies apps and URLs into productive, unproductive, or neutral categories to calculate a productivity score.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b6b57d57-40f4-4d52-966d-761a1cafadb8', $q$Screenshot capture$q$, $q$Optional periodic screenshots for verification, available on the Premium plan.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b6b57d57-40f4-4d52-966d-761a1cafadb8', $q$Project and task tracking$q$, $q$Allocates tracked time to specific projects or client work for billing and reporting.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b6b57d57-40f4-4d52-966d-761a1cafadb8', $q$Shift scheduling and absence calendar$q$, $q$Manages employee shifts and tracks absences alongside time-tracking data.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b6b57d57-40f4-4d52-966d-761a1cafadb8', $q$Offline time tracking$q$, $q$Manually logs time spent away from the computer, such as meetings or field work.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b6b57d57-40f4-4d52-966d-761a1cafadb8', $q$Pomodoro timer$q$, $q$Built-in focus timer to help employees manage work sessions and breaks.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b6b57d57-40f4-4d52-966d-761a1cafadb8', $q$Automated invoicing$q$, $q$Generates invoices automatically based on tracked billable hours.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b6b57d57-40f4-4d52-966d-761a1cafadb8', $q$Fully automatic tracking removes the need for employees to manually start and stop timers.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b6b57d57-40f4-4d52-966d-761a1cafadb8', $q$Built-in productivity scoring works out of the box with minimal configuration.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b6b57d57-40f4-4d52-966d-761a1cafadb8', $q$Free plan available for single users, making it accessible for freelancers.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b6b57d57-40f4-4d52-966d-761a1cafadb8', $q$Combines time tracking, scheduling, and invoicing in a single product.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b6b57d57-40f4-4d52-966d-761a1cafadb8', $q$Screenshot capture and scheduling tools are gated behind the higher Premium tier.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b6b57d57-40f4-4d52-966d-761a1cafadb8', $q$Employee monitoring features like screenshots can raise privacy concerns among tracked staff.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b6b57d57-40f4-4d52-966d-761a1cafadb8', $q$Free tier is limited to a single user, so teams must move to a paid plan almost immediately.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b6b57d57-40f4-4d52-966d-761a1cafadb8', $q$Enterprise pricing is not publicly listed and requires contacting sales.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b6b57d57-40f4-4d52-966d-761a1cafadb8', $q$Is DeskTime free?$q$, $q$DeskTime offers a free plan limited to a single user, along with a 14-day free trial for teams evaluating the paid Pro and Premium plans.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b6b57d57-40f4-4d52-966d-761a1cafadb8', $q$How much does DeskTime cost for teams?$q$, $q$DeskTime's Pro plan costs $7 per user per month ($6.42 when billed annually), and the Premium plan costs $10 per user per month with screenshots and scheduling included.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b6b57d57-40f4-4d52-966d-761a1cafadb8', $q$Does DeskTime take screenshots?$q$, $q$Screenshot capture is available on DeskTime's Premium plan as an optional monitoring feature.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b6b57d57-40f4-4d52-966d-761a1cafadb8', $q$Who created DeskTime?$q$, $q$DeskTime was created in 2011 by Draugiem Group, a Latvia-based technology company, originally as an internal productivity-tracking tool for its draugiem.lv social platform.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b6b57d57-40f4-4d52-966d-761a1cafadb8', $q$Does DeskTime track time automatically?$q$, $q$Yes, DeskTime automatically starts and stops time tracking based on computer activity, without requiring employees to manually start a timer.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b6b57d57-40f4-4d52-966d-761a1cafadb8', $q$What is DeskTime's productivity score?$q$, $q$DeskTime calculates a productivity score by classifying tracked applications and websites into productive, unproductive, or neutral categories, configurable by administrators.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b6b57d57-40f4-4d52-966d-761a1cafadb8', $q$Remote team productivity monitoring$q$, $q$Distributed teams use DeskTime to automatically track work hours and understand productivity patterns without manual timesheets.$q$, $q$Remote and hybrid team managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b6b57d57-40f4-4d52-966d-761a1cafadb8', $q$Freelance client billing$q$, $q$Freelancers use DeskTime's automatic tracking and invoicing to accurately bill clients for hours worked on specific projects.$q$, $q$Freelancers and contractors$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b6b57d57-40f4-4d52-966d-761a1cafadb8', $q$Outsourced team verification$q$, $q$Companies working with outsourced or contractor teams use DeskTime's screenshot capture and productivity reports to verify billed work.$q$, $q$Outsourcing and BPO managers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b6b57d57-40f4-4d52-966d-761a1cafadb8', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Single user","Automatic time tracking","Basic reports"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b6b57d57-40f4-4d52-966d-761a1cafadb8', $q$Pro$q$, $q$$7/user/month ($6.42 annual)$q$, $q$Monthly or annual$q$, NULL, $q$["Automatic tracking","Productivity scoring","Project tracking"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b6b57d57-40f4-4d52-966d-761a1cafadb8', $q$Premium$q$, $q$$10/user/month$q$, $q$Monthly or annual$q$, NULL, $q$["Everything in Pro","Screenshots","Absence calendar","Shift scheduling","IP restrictions"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b6b57d57-40f4-4d52-966d-761a1cafadb8', $q$Enterprise$q$, $q$Custom$q$, $q$Annual contract$q$, NULL, $q$["Custom support","Advanced security","Volume pricing"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b6b57d57-40f4-4d52-966d-761a1cafadb8', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$DeskTime is an automatic time-tracking and productivity monitoring tool for remote and on-site teams, using a desktop/mobile agent that starts and stops tracking automatically and classifies app and URL usage into productive or unproductive categories.$q$, $q$Created in 2011 by Latvia-based Draugiem Group as an internal tool to measure productivity on its draugiem.lv social platform, DeskTime is now a standalone commercial product headquartered in Riga, Latvia, with offices across Europe and the US.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b6b57d57-40f4-4d52-966d-761a1cafadb8', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$DeskTime automatically tracks time based on computer activity without requiring employees to manually start timers, and calculates a productivity score based on configurable app/URL categorization.$q$, $q$The platform includes project and task tracking, optional screenshot capture, shift scheduling and absence calendars, offline time tracking, a Pomodoro focus timer, and automated invoicing based on billable hours.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b6b57d57-40f4-4d52-966d-761a1cafadb8', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$DeskTime offers a free tier for single users and a 14-day free trial for teams, with the Pro plan at $7/user/month ($6.42 billed annually) and Premium at $10/user/month adding screenshots and scheduling.$q$, $q$An Enterprise plan with custom pricing is available for larger organizations needing additional support and security requirements.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b6b57d57-40f4-4d52-966d-761a1cafadb8', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b6b57d57-40f4-4d52-966d-761a1cafadb8', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b6b57d57-40f4-4d52-966d-761a1cafadb8', 'f24fb236-dfcf-452c-9b9e-02926f4383d9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b6b57d57-40f4-4d52-966d-761a1cafadb8', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b6b57d57-40f4-4d52-966d-761a1cafadb8', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b6b57d57-40f4-4d52-966d-761a1cafadb8', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b6b57d57-40f4-4d52-966d-761a1cafadb8', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4697278a-138a-4bf7-873d-8d71a39b66c4', $q$OpenFeature-native SDKs$q$, $q$Built around the CNCF OpenFeature standard, reducing vendor lock-in for feature flag evaluation code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4697278a-138a-4bf7-873d-8d71a39b66c4', $q$Real-time flag propagation$q$, $q$EdgeDB data layer propagates flag changes to connected clients with low latency.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4697278a-138a-4bf7-873d-8d71a39b66c4', $q$Percentage rollouts and targeting$q$, $q$Roll out features to a percentage of users or specific audience segments defined by custom rules.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4697278a-138a-4bf7-873d-8d71a39b66c4', $q$Unlimited flags, seats, and environments$q$, $q$Every pricing tier includes unlimited team seats, projects, environments, and feature flags.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4697278a-138a-4bf7-873d-8d71a39b66c4', $q$Audit logging and permissions$q$, $q$Tracks who changed which flag and when, with role-based access control on paid tiers.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4697278a-138a-4bf7-873d-8d71a39b66c4', $q$Stale flag detection$q$, $q$Identifies feature flags no longer actively branching in code as cleanup candidates.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4697278a-138a-4bf7-873d-8d71a39b66c4', $q$AI-generated flag summaries$q$, $q$Automatically summarizes flag configuration and status changes for easier team review.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4697278a-138a-4bf7-873d-8d71a39b66c4', $q$A/B testing and experimentation$q$, $q$Supports experimentation workflows inherited from the platform's Taplytics origins.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4697278a-138a-4bf7-873d-8d71a39b66c4', $q$Usage-based pricing with unlimited seats avoids per-teammate cost scaling common with competitors.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4697278a-138a-4bf7-873d-8d71a39b66c4', $q$OpenFeature-native design reduces vendor lock-in risk for engineering teams.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4697278a-138a-4bf7-873d-8d71a39b66c4', $q$Generous free tier (1,000 MAUs, unlimited flags) makes it accessible for small projects.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4697278a-138a-4bf7-873d-8d71a39b66c4', $q$Stale flag detection and AI summaries help manage feature-flag technical debt over time.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4697278a-138a-4bf7-873d-8d71a39b66c4', $q$Smaller funding history and team size compared to category leader LaunchDarkly.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4697278a-138a-4bf7-873d-8d71a39b66c4', $q$Recent acquisition by Dynatrace (January 2026) introduces uncertainty about long-term product roadmap and standalone pricing.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4697278a-138a-4bf7-873d-8d71a39b66c4', $q$Business tier at $500/month with annual billing may be a steep jump from the Developer plan for growing teams.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4697278a-138a-4bf7-873d-8d71a39b66c4', $q$Overage charges for MAUs and events require careful usage monitoring to avoid unexpected costs.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4697278a-138a-4bf7-873d-8d71a39b66c4', $q$What is DevCycle used for?$q$, $q$DevCycle is a feature flag management platform that lets engineering teams control feature rollouts, targeting, and experimentation in code without redeploying, enabling practices like canary releases and kill switches.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4697278a-138a-4bf7-873d-8d71a39b66c4', $q$Is DevCycle free?$q$, $q$Yes, DevCycle has a Free Forever plan that includes 1,000 client-side monthly active users with unlimited feature flags and unlimited team seats.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4697278a-138a-4bf7-873d-8d71a39b66c4', $q$What does OpenFeature-native mean for DevCycle?$q$, $q$DevCycle's SDKs are built around the CNCF-backed OpenFeature open standard, giving engineering teams a vendor-neutral API for feature flag evaluation that reduces lock-in to a single provider.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4697278a-138a-4bf7-873d-8d71a39b66c4', $q$Who owns DevCycle?$q$, $q$DevCycle was acquired by observability company Dynatrace in January 2026, after previously operating as an independent, VC-backed company headquartered in Toronto, Canada.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4697278a-138a-4bf7-873d-8d71a39b66c4', $q$How is DevCycle priced?$q$, $q$DevCycle uses usage-based pricing tied to monthly active users and event volume, with unlimited seats, projects, and flags on every tier, ranging from a free plan to a $500/month Business plan billed annually.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4697278a-138a-4bf7-873d-8d71a39b66c4', $q$Who are DevCycle's main competitors?$q$, $q$DevCycle competes with LaunchDarkly, Split.io, Flagsmith, Statsig, and PostHog's feature flag module in the feature management category.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4697278a-138a-4bf7-873d-8d71a39b66c4', $q$Controlled feature rollouts$q$, $q$Engineering teams use DevCycle to gradually roll out new features to a percentage of users, reducing the blast radius of bugs in production.$q$, $q$Software engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4697278a-138a-4bf7-873d-8d71a39b66c4', $q$Kill switches for risky features$q$, $q$Teams use DevCycle flags as kill switches to instantly disable a problematic feature in production without a code deployment.$q$, $q$Platform and reliability engineers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4697278a-138a-4bf7-873d-8d71a39b66c4', $q$A/B testing and experimentation$q$, $q$Product teams use DevCycle's targeting rules and experimentation workflows to test feature variants with specific user segments.$q$, $q$Product managers and growth engineers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4697278a-138a-4bf7-873d-8d71a39b66c4', $q$Free Forever$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["1,000 client-side MAUs","Unlimited flags","Unlimited seats"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4697278a-138a-4bf7-873d-8d71a39b66c4', $q$Developer$q$, $q$From $10/month$q$, $q$Usage-based, monthly$q$, NULL, $q$["Expanded MAU allocation","Unlimited flags and seats"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4697278a-138a-4bf7-873d-8d71a39b66c4', $q$Business$q$, $q$$500/month$q$, $q$Billed annually, usage-based overages$q$, NULL, $q$["100,000 MAUs","500,000 events/month","Audit logging","Roles and permissions","EdgeDB","Stale flag detection","AI summaries"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4697278a-138a-4bf7-873d-8d71a39b66c4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$DevCycle is an OpenFeature-native feature flag management platform that lets engineering teams control feature rollouts, targeting, and experimentation through code, decoupling feature release from code deployment.$q$, $q$The product's roots trace to Taplytics, a Y Combinator-backed A/B testing platform founded in 2011 by Cobi Druxerman, Jonathan Norris, and Andrew Norris; the team rebuilt it as DevCycle in 2022. DevCycle is headquartered in Toronto, Canada, and was acquired by observability company Dynatrace in January 2026.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4697278a-138a-4bf7-873d-8d71a39b66c4', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$DevCycle provides SDKs across many languages that evaluate feature flags locally or via its EdgeDB real-time data layer, supporting boolean, string, number, and JSON flag types with percentage-based rollouts and audience targeting.$q$, $q$The platform includes unlimited environments, projects, and feature flags on every tier, plus audit logging, role-based permissions, AI-generated flag summaries, and stale flag detection to reduce feature-flag technical debt.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4697278a-138a-4bf7-873d-8d71a39b66c4', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$DevCycle uses usage-based pricing tied to monthly active users (MAUs) and event volume rather than seats, with a Free Forever plan (1,000 MAUs, unlimited flags and seats) and a Developer plan starting at $10/month.$q$, $q$The Business plan is $500/month (billed annually) for 100,000 MAUs and 500,000 events, adding audit logging, EdgeDB, and AI summaries, with overages billed per additional 1,000 MAUs or 10,000 events.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4697278a-138a-4bf7-873d-8d71a39b66c4', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4697278a-138a-4bf7-873d-8d71a39b66c4', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4697278a-138a-4bf7-873d-8d71a39b66c4', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4697278a-138a-4bf7-873d-8d71a39b66c4', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9fc7c07a-2f39-4616-b762-2e97af017f6e', $q$Agentless discovery$q$, $q$Discovers physical, virtual, network, and cloud infrastructure without installing agents on every endpoint.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9fc7c07a-2f39-4616-b762-2e97af017f6e', $q$Application dependency mapping$q$, $q$Automatically visualizes how servers and applications interconnect to inform migration planning and change management.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9fc7c07a-2f39-4616-b762-2e97af017f6e', $q$CMDB$q$, $q$Maintains an accurate, continuously updated configuration management database that can feed external ITSM tools.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9fc7c07a-2f39-4616-b762-2e97af017f6e', $q$IP address management$q$, $q$Tracks and manages IP address allocation across the discovered infrastructure.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9fc7c07a-2f39-4616-b762-2e97af017f6e', $q$Software license management$q$, $q$Tracks installed software across the environment for license compliance reporting.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9fc7c07a-2f39-4616-b762-2e97af017f6e', $q$Data center infrastructure management$q$, $q$Rack elevation diagrams, power draw tracking, and environmental monitoring for physical data centers.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9fc7c07a-2f39-4616-b762-2e97af017f6e', $q$ServiceNow and ITSM integrations$q$, $q$Pushes discovered configuration item data into external ITSM platforms like ServiceNow.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9fc7c07a-2f39-4616-b762-2e97af017f6e', $q$Migration planning$q$, $q$Uses actual dependency and traffic-flow data to plan data center and cloud migrations.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9fc7c07a-2f39-4616-b762-2e97af017f6e', $q$Agentless discovery reduces deployment overhead for large, heterogeneous data center environments.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9fc7c07a-2f39-4616-b762-2e97af017f6e', $q$Broad coverage spanning physical, virtual, network, and cloud infrastructure in a single platform.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9fc7c07a-2f39-4616-b762-2e97af017f6e', $q$Now backed by Freshworks' resources and broader ITSM product portfolio following the 2024 acquisition.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9fc7c07a-2f39-4616-b762-2e97af017f6e', $q$Detailed dependency mapping helps reduce risk when planning migrations or infrastructure changes.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9fc7c07a-2f39-4616-b762-2e97af017f6e', $q$Pricing tiers scale by device count, which can become expensive quickly for larger environments.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9fc7c07a-2f39-4616-b762-2e97af017f6e', $q$Full pricing is not self-serve and often requires contacting sales for anything beyond entry tiers.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9fc7c07a-2f39-4616-b762-2e97af017f6e', $q$Additional modules (dependency mapping, license management) are licensed separately, adding to total cost.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9fc7c07a-2f39-4616-b762-2e97af017f6e', $q$Product roadmap and standalone identity may shift over time as it integrates further into Freshworks.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9fc7c07a-2f39-4616-b762-2e97af017f6e', $q$What is Device42 used for?$q$, $q$Device42 is used for agentless IT asset discovery, application dependency mapping, and maintaining a configuration management database (CMDB) across data center and cloud infrastructure.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9fc7c07a-2f39-4616-b762-2e97af017f6e', $q$Who owns Device42 now?$q$, $q$Device42 was acquired by Freshworks in April 2024 in a deal reported at approximately $230 million, and now operates as 'Device42, A Freshworks Company.'$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9fc7c07a-2f39-4616-b762-2e97af017f6e', $q$How much does Device42 cost?$q$, $q$Device42 pricing is tiered by device count, starting at roughly $1,449 per year for up to 100 devices and scaling to roughly $9,999 per year for up to 2,500 devices, with custom pricing above that.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9fc7c07a-2f39-4616-b762-2e97af017f6e', $q$Does Device42 require agents installed on servers?$q$, $q$No, Device42 uses agentless discovery to identify and inventory physical, virtual, network, and cloud infrastructure without requiring software agents on every endpoint.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9fc7c07a-2f39-4616-b762-2e97af017f6e', $q$Does Device42 integrate with ServiceNow?$q$, $q$Yes, Device42 can push discovered configuration item data into external ITSM platforms including ServiceNow.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9fc7c07a-2f39-4616-b762-2e97af017f6e', $q$When was Device42 founded?$q$, $q$Device42 was founded in 2010 and was originally based in West Haven, Connecticut, before its 2024 acquisition by Freshworks.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9fc7c07a-2f39-4616-b762-2e97af017f6e', $q$Data center migration planning$q$, $q$IT teams use Device42's dependency mapping to understand application interdependencies before migrating servers to the cloud or a new data center.$q$, $q$Infrastructure and migration teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9fc7c07a-2f39-4616-b762-2e97af017f6e', $q$CMDB accuracy and ITSM integration$q$, $q$Organizations use Device42 to maintain an accurate, automatically updated CMDB that feeds into ServiceNow or other ITSM platforms.$q$, $q$IT service management teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9fc7c07a-2f39-4616-b762-2e97af017f6e', $q$Software license compliance$q$, $q$IT asset managers use Device42's software license management module to track installed software and avoid compliance risk.$q$, $q$IT asset management teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9fc7c07a-2f39-4616-b762-2e97af017f6e', $q$Core (1-100 devices)$q$, $q$$1,449/year$q$, $q$Annual$q$, NULL, $q$["Up to 100 devices","Up to 1,000 IPs","Core discovery"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9fc7c07a-2f39-4616-b762-2e97af017f6e', $q$Core (101-500 devices)$q$, $q$$2,999/year$q$, $q$Annual$q$, NULL, $q$["Up to 500 devices","Up to 5,000 IPs"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9fc7c07a-2f39-4616-b762-2e97af017f6e', $q$Core (501-1,000 devices)$q$, $q$$4,999/year$q$, $q$Annual$q$, NULL, $q$["Up to 1,000 devices","Up to 10,000 IPs"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9fc7c07a-2f39-4616-b762-2e97af017f6e', $q$Core (1,001-2,500 devices)$q$, $q$~$9,999/year$q$, $q$Annual$q$, NULL, $q$["Up to 2,500 devices"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9fc7c07a-2f39-4616-b762-2e97af017f6e', $q$Core (2,500+ devices)$q$, $q$Custom$q$, $q$Annual$q$, NULL, $q$["Custom quote for large deployments"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9fc7c07a-2f39-4616-b762-2e97af017f6e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Device42 is an agentless IT asset discovery, dependency mapping, and CMDB platform used by IT operations teams to inventory and understand relationships across physical, virtual, network, and cloud infrastructure.$q$, $q$Founded in 2010 in West Haven, Connecticut, Device42 was acquired by Freshworks in April 2024 in a roughly $230 million cash-and-equity deal, and now operates as 'Device42, A Freshworks Company' from Freshworks' San Mateo, California headquarters.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9fc7c07a-2f39-4616-b762-2e97af017f6e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Device42 discovers physical servers, virtual machines, network devices, storage, and cloud resources without requiring agents on every endpoint, continuously updating an accurate infrastructure inventory.$q$, $q$The platform's application dependency mapping visualizes how servers and services interconnect, helping teams plan migrations and understand change blast radius, while add-on modules cover IP address management, software license management, and data center power/environmental monitoring.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9fc7c07a-2f39-4616-b762-2e97af017f6e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Device42 is priced on annual subscription tiers based on the number of managed devices, ranging from about $1,449/year for up to 100 devices to about $9,999/year for up to 2,500 devices, with custom quotes above that.$q$, $q$Additional discovery modules like Application Dependency Mapping and Software License Management are licensed separately from the base Core tier, and a free trial is available.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9fc7c07a-2f39-4616-b762-2e97af017f6e', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9fc7c07a-2f39-4616-b762-2e97af017f6e', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9fc7c07a-2f39-4616-b762-2e97af017f6e', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9fc7c07a-2f39-4616-b762-2e97af017f6e', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Autonomous task execution$q$, $q$Devin plans, writes, tests, debugs, and ships a pull request for a task with minimal human intervention.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Sandboxed development environment$q$, $q$Operates in an isolated environment with shell access, code execution, and version control integration.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$IDE and Slack integration$q$, $q$Assign and monitor Devin's tasks directly from an IDE plugin or conversationally through Slack.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Parallel sessions$q$, $q$Runs multiple Devin sessions on different tasks simultaneously rather than one task at a time.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Knowledge base and playbooks$q$, $q$Teams codify repository conventions and process rules that Devin references on future tasks.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$DeepWiki documentation$q$, $q$Companion tool that auto-generates and maintains documentation/wikis for codebases.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Self-hosted enterprise deployment$q$, $q$Enterprise customers can deploy Devin within their own infrastructure with custom security controls.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Agentic Computing Unit billing$q$, $q$Usage is metered in ACUs, a normalized unit representing compute, inference, and networking used per task.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Capable of end-to-end task ownership, from planning through shipped pull request, rather than just code completion.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Adopted in production by large regulated enterprises including major banks and defense branches.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Usage-based ACU pricing lets individuals start for as little as $20/month without a large upfront commitment.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Enterprise self-hosted deployment option supports strict data-control and security requirements.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$ACU-based pricing can be difficult to predict in advance compared to flat per-seat pricing.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Core plan caps concurrent sessions at 10, requiring the pricier Team plan for higher-volume usage.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$As a rapidly scaling, richly funded startup, pricing and product terms may continue to change.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Autonomous agent output on complex, ambiguous tasks may still require human review before merging.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$What is Devin AI?$q$, $q$Devin is an autonomous AI software engineering agent built by Cognition AI that plans, writes, tests, debugs, and ships pull requests for coding tasks with minimal human intervention.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$How much does Devin cost?$q$, $q$Devin's Core plan starts at $20/month with pay-as-you-go billing at $2.25 per Agentic Computing Unit (ACU); the Team plan is $500/month with 250 included ACUs, and Enterprise pricing is custom.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$What is an ACU in Devin's pricing?$q$, $q$An Agentic Computing Unit (ACU) is Devin's normalized measure of compute, model inference, and networking resources used while actively working on a task, with roughly one ACU equal to 15 minutes of active autonomous work.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Who founded Devin and Cognition AI?$q$, $q$Cognition AI was founded in November 2023 by Scott Wu, Steven Hao, and Walden Yan, and launched Devin in March 2024.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Which companies use Devin?$q$, $q$Enterprise customers reported to use Devin in production include Citi, Goldman Sachs, Mercedes-Benz, Dell, Santander, and branches of the US military including the Army and Navy.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$How is Devin different from GitHub Copilot or Cursor?$q$, $q$Devin is designed for full task autonomy, taking a task from description through a shipped pull request, whereas Copilot and Cursor primarily assist a human engineer during active coding rather than owning tasks end to end.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Backlog and bug-fix automation$q$, $q$Engineering teams assign Devin well-scoped bug fixes, dependency upgrades, and boilerplate feature work to clear backlog without engineer time.$q$, $q$Software engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Enterprise engineering augmentation$q$, $q$Large regulated enterprises deploy Devin within their own infrastructure to autonomously handle routine engineering tasks under strict security controls.$q$, $q$Enterprise engineering organizations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Test writing and documentation$q$, $q$Teams use Devin to autonomously write test suites and use DeepWiki to generate and maintain codebase documentation.$q$, $q$QA and developer experience teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Core$q$, $q$$20/month + $2.25/ACU$q$, $q$Monthly, pay-as-you-go$q$, NULL, $q$["Unlimited seats","Up to 10 concurrent sessions","Pay-as-you-go ACU billing"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Team$q$, $q$$500/month$q$, $q$Monthly$q$, NULL, $q$["250 included ACUs (~62.5 hours)","Unlimited concurrent sessions","$2.00/ACU effective rate"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$Enterprise$q$, $q$Custom$q$, $q$Annual contract$q$, NULL, $q$["Self-hosted deployment","Custom security controls","Dedicated support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Devin is an autonomous AI software engineering agent from Cognition AI that independently plans, writes, tests, debugs, and ships pull requests for a given task, distinguishing it from developer-assist tools that require constant human guidance.$q$, $q$Cognition was founded in November 2023 by Scott Wu, Steven Hao, and Walden Yan, and launched Devin in March 2024 as what it called the 'world's first AI software engineer.' The company is headquartered in San Francisco and raised over $1 billion in May 2026 at a $26 billion post-money valuation.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Devin operates in a sandboxed development environment where it can browse documentation, write and execute code, run tests, use a shell, and manage version control autonomously across multi-step tasks.$q$, $q$The platform integrates via an IDE plugin and Slack, supports multiple parallel sessions, and uses a knowledge base/playbook system so teams can codify repository-specific conventions that Devin references on future tasks.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Devin is priced using Agentic Computing Units (ACUs), a normalized measure of compute and inference used per task, with roughly one ACU equal to 15 minutes of active work.$q$, $q$The Core plan starts at $20/month with pay-as-you-go billing at $2.25/ACU, the Team plan is $500/month with 250 included ACUs (~62.5 hours), and Enterprise offers custom, self-hosted deployment pricing.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1da348da-ba26-4700-9ed2-47edb28b71cd', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
